// Mapeia body.action -> spotifyOp (chaves do Switch n8n: pause, resume, nextSong, …).
// IMPORTANTE: o Switch NÃO tem chave "play" — só "resume". Por isso play → resume.

const root = $input.first().json;
const body = root.body && typeof root.body === 'object' ? root.body : root;
const pickAction = () => {
  if (body && typeof body.action === 'string' && body.action.trim()) return body.action;
  if (body && typeof body.command === 'string' && body.command.trim()) return body.command;
  if (body && typeof body.intent === 'string' && body.intent.trim()) return body.intent;
  return '';
};

const raw = String(pickAction())
  .toLowerCase()
  .trim();

const normalized = raw
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/\s+/g, '_');

const map = {
  pause: 'pause',
  play: 'resume',
  resume: 'resume',
  start: 'resume',
  unpause: 'resume',
  continue: 'resume',
  continuar: 'resume',
  retomar: 'resume',
  despausar: 'resume',
  next: 'nextSong',
  skip: 'nextSong',
  previous: 'previousSong',
  back: 'previousSong',
  volume: 'volume',
  playlist: 'listPlaylists',
  play_playlist: 'startMusic',
  list_playlists: 'listPlaylists',
  playlists: 'listPlaylists',
  listar_playlists: 'listPlaylists',
  trocar_playlist: 'switchPlaylist',
  switch_playlist: 'switchPlaylist',
  change_playlist: 'switchPlaylist',
  tocar_musica: 'playTrack',
  play_track: 'playTrack',
  track: 'playTrack',
  tocar_genero: 'playGenre',
  play_genre: 'playGenre',
  genre: 'playGenre',
};

let spotifyOp = map[raw] || map[normalized];

const parsePercent = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(String(value).replace(',', '.'));
  if (!Number.isFinite(n)) return null;
  return Math.max(0, Math.min(100, Math.round(n)));
};

const upWords = /\b(up|increase|raise|higher|louder|aumentar|mais|alto)\b/i;
const downWords = /\b(down|decrease|lower|quieter|softer|abaixar|baixar|diminuir|menos|baixo)\b/i;

const actionMentionsVolume = /\b(volume|som|audio|áudio)\b/i.test(raw);
const hasExplicitVolumeField =
  body.volume_percent !== undefined ||
  body.volume !== undefined ||
  body.volume_delta !== undefined ||
  body.delta !== undefined;

if ((actionMentionsVolume && (upWords.test(raw) || downWords.test(raw))) || hasExplicitVolumeField) {
  spotifyOp = 'volume';
}

// Health check/ping interno do Orbital.
if (raw === '__orbital_connectivity_probe__') {
  spotifyOp = 'healthcheck';
}

// play / resume / start + dados de faixa -> tocar música específica (não só retomar).
// Sem isso, action:play + track_name ia para Resume e ignorava o nome.
const hasTrackTarget = Boolean(
  (body.track_uri && String(body.track_uri).trim()) ||
  (body.track_id && String(body.track_id).trim()) ||
  (body.track_name && String(body.track_name).trim()) ||
  (body.track_query && String(body.track_query).trim()) ||
  (body.track && String(body.track).trim()) ||
  (body.song && String(body.song).trim()) ||
  (body.music && String(body.music).trim()) ||
  (body.query &&
    String(body.query).trim() &&
    !body.playlist_uri &&
    !body.context_uri) ||
  (body.artist && String(body.artist).trim()) ||
  (body.artista && String(body.artista).trim())
);
if (hasTrackTarget && spotifyOp === 'resume' && raw !== '__orbital_connectivity_probe__') {
  spotifyOp = 'playTrack';
}

// Desambiguação: "playlist" sem URI/ID -> listar; com URI/ID -> tocar/trocar.
if (raw === 'playlist' || normalized === 'playlist') {
  const hasContext = Boolean(
    body.playlist_uri || body.uri || body.context_uri || body.playlist_id
  );
  spotifyOp = hasContext ? 'switchPlaylist' : 'listPlaylists';
}

if (!spotifyOp) {
  // Linguagem natural no campo action, ex: "toca a paixão me levou pfv"
  if (/^(toca|toque|tocar|play)\b/.test(raw)) {
    spotifyOp = 'playTrack';
    if (!body.track_query && !body.track_name && !body.track && !body.song && !body.music && !body.query) {
      const extracted = raw
        .replace(/^(toca|toque|tocar|play)\s+/i, '')
        .replace(/\b(pfv|por favor)\b/gi, '')
        .trim();
      if (extracted) body.track_query = extracted;
    }
  } else if (
    /\bplaylist(s)?\b/.test(raw) &&
    /\b(quais|quantas|minhas|lista|listar|mostrar|ver|tenho|salva|salvas|cadastrada|cadastradas|guardada|guardadas)\b/.test(raw)
  ) {
    spotifyOp = 'listPlaylists';
  }
}

if (!spotifyOp) {
  spotifyOp = 'unsupported';
}

if (spotifyOp === 'volume') {
  const explicitPercent = parsePercent(body.volume_percent);
  const explicitVolume = parsePercent(body.volume);
  const deltaRaw = parsePercent(body.volume_delta ?? body.delta);

  if (explicitPercent !== null) {
    body.volume_percent = explicitPercent;
  } else if (explicitVolume !== null) {
    body.volume_percent = explicitVolume;
  } else if (deltaRaw !== null) {
    const base = 50;
    const sign = downWords.test(raw) ? -1 : 1;
    body.volume_percent = Math.max(0, Math.min(100, base + sign * deltaRaw));
  } else if (downWords.test(raw)) {
    body.volume_percent = 35;
  } else if (upWords.test(raw)) {
    body.volume_percent = 65;
  } else {
    body.volume_percent = 50;
  }
}

return [{ json: { spotifyOp, body, action: raw, normalizedAction: normalized } }];

const items = $input.all().map(i => i.json || {});
const playlists = items.map((p) => ({
  id: p.id,
  uri: p.uri,
  name: p.name,
  owner: p.owner?.display_name || p.owner?.id || null,
  tracks: p.tracks?.total ?? null,
  public: p.public ?? null,
}));
return [{ json: { playlists, total: playlists.length } }];

const body = $json.body || {};
const rawAction = String($json.action || '').trim();
const normalizedAction = String($json.normalizedAction || '').trim();

const directUri = body.track_uri || body.uri || body.track_id || null;
if (directUri) {
  return [{ json: { ...$json, trackUri: directUri, trackQuery: null } }];
}

let q =
  body.track_query ||
  body.track_name ||
  body.track ||
  body.song ||
  body.music ||
  body.query ||
  '';

if (!q && (rawAction || normalizedAction)) {
  const source = normalizedAction || rawAction.toLowerCase();
  q = source
    .replace(/^tocar?_?musica_?/i, '')
    .replace(/^play_?track_?/i, '')
    .replace(/^toca_?/i, '')
    .replace(/^play_?/i, '')
    .replace(/_?pfv$/i, '')
    .replace(/_?por_favor$/i, '')
    .replace(/_/g, ' ')
    .trim();
}

const artist = String(body.artist || body.artista || '').trim();

if (!q && !artist) {
  return [{ json: { error: true, message: 'Para tocar música específica, envie track_uri/track_id ou track_name ou artist.' } }];
}

let trackQuery;
if (!q && artist) {
  trackQuery = `artist:${artist}`;
} else if (q && artist) {
  trackQuery = `track:${q} artist:${artist}`;
} else {
  trackQuery = q;
}
return [{ json: { ...$json, trackQuery } }];

const inItem = $input.first().json || {};
if (inItem.error) return [{ json: inItem }];

const uri = inItem.uri || null;
if (!uri) {
  return [{ json: { error: true, message: `Nao encontrei faixa para: ${$json.trackQuery || 'consulta vazia'}` } }];
}

return [{ json: { ...$json, trackUri: uri, matchedTrack: inItem.name || null, matchedArtist: inItem.artists?.[0]?.name || null } }];

const prev = $('Pick track URI').first().json || {};
const dev = $input.first().json || {};
return [{ json: { ...prev, ...dev, trackUri: prev.trackUri } }];

const body = $json.body || {};
const raw = String(body.genre || body.genero || '').trim().toLowerCase();
const byGenre = {
  pop: 'spotify:playlist:37i9dQZF1DXcBWIGoYBM5M',
  rock: 'spotify:playlist:37i9dQZF1DWXRqgorJj26U',
  jazz: 'spotify:playlist:37i9dQZF1DXbITWG1ZJKYt',
  lofi: 'spotify:playlist:37i9dQZF1DXdxcBWuJkbcy',
  'lo-fi': 'spotify:playlist:37i9dQZF1DXdxcBWuJkbcy',
  eletronic: 'spotify:playlist:37i9dQZF1DX4dyzvuaRJ0n',
  eletrônica: 'spotify:playlist:37i9dQZF1DX4dyzvuaRJ0n',
  electronic: 'spotify:playlist:37i9dQZF1DX4dyzvuaRJ0n',
  funk: 'spotify:playlist:37i9dQZF1DXaXB8fQg7xif',
  rap: 'spotify:playlist:37i9dQZF1DX0XUsuxWHRQd',
  hiphop: 'spotify:playlist:37i9dQZF1DX0XUsuxWHRQd',
  hip_hop: 'spotify:playlist:37i9dQZF1DX0XUsuxWHRQd',
  classica: 'spotify:playlist:37i9dQZF1DWWEJlAGA9gs0',
  clássica: 'spotify:playlist:37i9dQZF1DWWEJlAGA9gs0',
  classical: 'spotify:playlist:37i9dQZF1DWWEJlAGA9gs0',
};
const genreUri = byGenre[raw] || body.playlist_uri || body.uri || null;
if (!genreUri) {
  return [{ json: { error: true, message: 'Genero nao reconhecido. Envie genre ou playlist_uri.' } }];
}
return [{ json: { ...$json, genreUri } }];

return [{
  json: {
    error: true,
    message: 'Acao nao suportada pelo no nativo Spotify no n8n (ex.: shuffle, repeat). '
      + 'Use outro fluxo com HTTP Request ou escolha: pause, play, resume, next, previous, volume, playlist, '
      + 'list_playlists, switch_playlist, play_track, play_genre.'
  }
}];

const root = $input.first().json || {};
const devices = root.devices || root.body?.devices || [];
if (!devices.length) {
  return [{
    json: {
      error: true,
      message:
        'Nenhum dispositivo Spotify disponivel. Abra o app Spotify no celular, PC ou Web Player '
        + '(play.spotify.com) e faca login nesta mesma conta; depois tente de novo.'
    }
  }];
}
const usable = devices.filter((d) => d && d.id && !d.is_restricted);
if (!usable.length) {
  return [{ json: { error: true, message: 'Dispositivos encontrados, mas nenhum permite reproducao.' } }];
}
const score = (d) => {
  const t = String(d.type || '').toLowerCase();
  if (t === 'computer') return 0;
  if (t === 'smartphone') return 1;
  if (t === 'tablet') return 2;
  return 5;
};
usable.sort((a, b) => score(a) - score(b));
const active = usable.find((d) => d.is_active);
const pick = active || usable[0];
return [{
  json: {
    deviceId: pick.id,
    deviceName: pick.name || '',
    deviceType: pick.type || ''
  }
}];

